import type { ReactNode } from 'react';
import type {
  DatePickerProps as AriaDatePickerProps,
  DateValue,
} from 'react-aria-components';
import { DatePicker as BaseDatePicker } from '@/components/atoms/DatePicker';
import { HintText } from '@/components/atoms/Input/base/hint-text';
import { Label } from '@/components/atoms/Input/base/label';
import { cx } from '@/utils/cx';
import { WithDataId } from '@/types/withDataId';

export interface DatePickerFieldProps
  extends AriaDatePickerProps<DateValue>, WithDataId {
  /** Label text for the date picker */
  label?: string;
  /** Helper text displayed below the date picker */
  hint?: ReactNode;
  /** Label tooltip message */
  tooltip?: string;
  /** Label tooltip description */
  tooltipDescription?: string;
  /** Custom class name for the wrapper */
  className?: string;
  /** Whether the field is required */
  required?: boolean;
}

export function DatePickerField({
  label,
  hint,
  tooltip,
  tooltipDescription,
  className,
  required,
  isRequired: isRequiredProp,
  isInvalid,
  ...props
}: DatePickerFieldProps) {
  // Merge required prop with isRequired for consistency with other components
  const isRequired = isRequiredProp ?? required;

  return (
    <div
      className={cx(
        'group flex h-max w-full flex-col items-start justify-start gap-1.5',
        className,
      )}
    >
      {label && (
        <Label
          isRequired={isRequired}
          tooltip={tooltip}
          tooltipDescription={tooltipDescription}
        >
          {label}
        </Label>
      )}

      <BaseDatePicker
        aria-label={!label ? 'Select date' : undefined}
        isRequired={isRequired}
        isInvalid={isInvalid}
        {...props}
      />

      {hint && <HintText isInvalid={isInvalid}>{hint}</HintText>}
    </div>
  );
}
